import './index.css';
import React, { useState } from 'react';
import Header from "./components/Header";
import Sidebar from './components/Sidebar';
import FormAgendamento from './FormAgendamento';
import ListaAgendamentos from './components/ListaAgendamentos';
import Modal from './Modal';

function App() {
  const [active, setActive] = useState('agendar');
  const [showModal, setShowModal] = useState(false);
  const [reloadAgendamentos, setReloadAgendamentos] = useState(0);
  const [agendamentoEditando, setAgendamentoEditando] = useState(null);

  // Abrir modal para criar novo
  function handleNovoClick() {
    setAgendamentoEditando(null);
    setShowModal(true);
  }

  // Quando finalizar/cadastrar/editar um agendamento
  function handleNovoAgendamento() {
    setReloadAgendamentos(r => r + 1);
    setShowModal(false);
    setAgendamentoEditando(null);
  }

  // Editar agendamento existente
  function handleEditarAgendamento(agendamento) {
    setAgendamentoEditando(agendamento);
    setShowModal(true);
  }

  // Cancelar edição/modal
  function handleFimEdicaoAgendamento() {
    setShowModal(false);
    setAgendamentoEditando(null);
  }

  // Conteúdo da rota agendar
  function renderConteudo() {
    if (active !== 'agendar') return <div>Selecione uma opção.</div>;
    return (
      <div>
        {/* Header da seção com botão */}
        <div className="flex justify-between items-center mb-6">
          <h1 className="text-2xl font-bold">Agendamentos</h1>
          <button
            className="bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700 transition"
            onClick={handleNovoClick}
          >
            Agendar Paciente
          </button>
        </div>
        {/* Lista de agendamentos */}
        <ListaAgendamentos
          reloadKey={reloadAgendamentos}
          onEditar={handleEditarAgendamento}
        />
        {/* Modal com Formulário */}
        {showModal && (
          <Modal onClose={handleFimEdicaoAgendamento}>
            <FormAgendamento
              onNovoAgendamento={handleNovoAgendamento}
              agendamentoEditando={agendamentoEditando}
              onFimEdicao={handleFimEdicaoAgendamento}
            />
          </Modal>
        )}
      </div>
    );
  }

  // Layout principal
  return (
    <div className="bg-[#F6F6F8] min-h-screen">
      <Header />
      <div className="flex">
        <Sidebar active={active} onMenuClick={setActive} />
        <main className="flex-1 ml-64 mt-16 p-8">
          <div className="max-w-4xl mx-auto">{renderConteudo()}</div>
        </main>
      </div>
    </div>
  );
}

export default App;
